import { useMotionValue, useSpring } from "motion/react";
import { useEffect, useRef } from "react";

export function useSmartHeader(headerPx = 64, snapDelay = 120) {
  const yRaw = useMotionValue(0); // 0 = fully shown
  const y = useSpring(yRaw, { stiffness: 400, damping: 40 });

  const lastY = useRef(0);
  const snapTimer = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    const onScroll = () => {
      const cur = window.scrollY;

      /* Always show at top, even if the user scrolled up slowly to the top */
      if (cur <= 50) {
        yRaw.set(0); // fully visible
        lastY.current = 0;
        return;
      }

      const delta = cur - lastY.current;
      lastY.current = cur;

      // move header opposite to scroll direction, clamped
      const next = Math.max(Math.min(yRaw.get() - delta, 0), -headerPx);
      yRaw.set(next);

      if (snapTimer.current !== null) {
        clearTimeout(snapTimer.current);
      }
      snapTimer.current = setTimeout(() => {
        const pos = yRaw.get();
        yRaw.set(pos < -headerPx / 2 ? -headerPx : 0); // snap
      }, snapDelay);
    };

    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, [headerPx, snapDelay, yRaw]);

  return y; // spring-smoothed motion value
}

"use client";

import { motion } from "motion/react";
import { useSmartHeader } from "@/use-smart-header";

export default function Header() {
  const y = useSmartHeader(100);

  return (
    <div className="pointer-events-none sticky top-0 z-50">
      <motion.header
        className="relative z-50 mx-auto flex max-w-3xl flex-row items-center gap-2 px-4 pt-8 md:gap-4"
        style={{ y }}
      >
        <div className="pointer-events-auto flex flex-1 items-center justify-between rounded-full bg-background/60 p-2 backdrop-blur-md">
          <div className="flex items-center gap-2 md:gap-4">
            <span>A</span>
            <span>B</span>
          </div>
          <div className="flex items-center gap-4">
            <span>C</span>
            <span>D</span>
          </div>
        </div>
      </motion.header>
    </div>
  );
}
